// satisfactionCheckerFunc is a test-local functional adapter for
// SatisfactionChecker.
type satisfactionCheckerFunc func(ctx context.Context, beadID string, noChangesCount int) (bool, string, error)

func (f satisfactionCheckerFunc) CheckSatisfied(ctx context.Context, beadID string, noChangesCount int) (bool, string, error) {
	return f(ctx, beadID, noChangesCount)
}

type backEdgeDecompositionStore struct {
	*bead.Store
	parentID string
}

func (s *backEdgeDecompositionStore) Create(ctx context.Context, b *bead.Bead) error {
	base := s.Store
	if err := base.Create(ctx, b); err != nil {
		return err
	}
	if b.Parent != s.parentID {
		return nil
	}
	return base.Update(ctx, b.ID, func(child *bead.Bead) {
		child.AddDep(s.parentID, "blocks")
	})
}

